function safeParse(text) {
  if (!text) return null;
  try {
    return JSON.parse(text);
  } catch (error) {
    const trimmed = String(text).trim();
    const start = trimmed.indexOf('{');
    const end = trimmed.lastIndexOf('}');
    if (start >= 0 && end > start) {
      try {
        return JSON.parse(trimmed.slice(start, end + 1));
      } catch (innerError) {
        return null;
      }
    }
    return null;
  }
}

return items.map((entry) => {
  const response = entry.json;
  const text = response.candidates?.[0]?.content?.parts?.[0]?.text || response.text || '';
  const parsed = safeParse(text) || {};
  const classification = ['strong', 'average', 'weak'].includes(String(parsed.classification || '').toLowerCase())
    ? String(parsed.classification).toLowerCase()
    : 'average';

  return {
    json: {
      ...entry.json,
      screeningScore: Number(parsed.score || 0),
      screeningClassification: classification,
      screeningSummary: String(parsed.summary || 'AI screening completed without a summary.').trim(),
      screeningStrengths: String(parsed.strengths || 'No strengths were returned by the model.').trim(),
      screeningConcerns: String(parsed.concerns || 'No concerns were returned by the model.').trim(),
      screeningRecommendation: String(parsed.interview_recommendation || 'Review manually.').trim(),
      contactStatus: 'pending'
    }
  };
});
